// src/games/blackjack/service.ts
async function getState(userId) {
  const active = await getActiveGame(userId);
  if (active) {
    return ok2({ game: sanitizeGame(active) });
  }
  const finished = await getGameForUser(userId);
  if (finished && finished.phase === "finished") {
    await persistRound(userId, finished);
    await syncBalance(userId, finished.balance);
    await clearGame(userId);
    return ok2({ game: sanitizeGame(finished) });
  }
  return ok2({ game: null });
}
async function deal(userId, bet) {
  if (await getActiveGame(userId)) {
    return err(ErrorCode.ACTIVE_GAME_EXISTS, "Finish or clear your current game first");
  }
  const { balance: currentBalance } = await findOrCreateBalance2(userId);
  if (currentBalance < bet) {
    return err(ErrorCode.INSUFFICIENT_FUNDS, `Insufficient funds: need ${bet}, have ${currentBalance}`, { required: bet, current: currentBalance });
  }
  const game = dealGame(bet, currentBalance, userId);
  await syncBalance(userId, game.balance);
  await saveGame(game);
  return ok2({ game: sanitizeGame(game) });
}
async function handleInsurance(userId, decision) {
  const game = await getActiveGame(userId);
  if (!game) {
    return err(ErrorCode.NO_ACTIVE_GAME);
  }
  if (game.phase !== "insurance") {
    return err(ErrorCode.INSURANCE_NOT_AVAILABLE);
  }
  let updated;
  try {
    updated = resolveInsurance(game, decision);
  } catch (e) {
    return err(ErrorCode.INSUFFICIENT_FUNDS, e.message);
  }
  await syncBalance(userId, updated.balance);
  if (updated.phase === "finished") {
    await persistRound(userId, updated);
  }
  await saveGame(updated);
  return ok2({ game: sanitizeGame(updated) });
}
async function handleAction(userId, action) {
  const game = await getActiveGame(userId);
  if (!game) {
    return err(ErrorCode.NO_ACTIVE_GAME);
  }
  if (game.phase === "insurance") {
    return err(ErrorCode.INSURANCE_PENDING);
  }
  if (game.phase !== "playing") {
    return err(ErrorCode.NOT_YOUR_TURN);
  }
  const hand = game.playerHands[game.activeHandIndex];
  if (!hand) {
    return err(ErrorCode.NO_ACTIVE_HAND);
  }
  if (hand.splitAces) {
    return err(ErrorCode.SPLIT_ACES_NO_ACTIONS);
  }
  const validationError = validateAction(action, game, hand);
  if (validationError)
    return validationError;
  let updated;
  try {
    updated = executeAction(action, game);
  } catch (e) {
    return err(ErrorCode.VALIDATION_ERROR, e.message);
  }
  if (shouldTriggerDealer(updated)) {
    updated = resolveDealerAndSettle(updated);
  }
  if (action === "double" || action === "split" || updated.phase === "finished") {
    await syncBalance(userId, updated.balance);
  }
  if (updated.phase === "finished") {
    await persistRound(userId, updated);
  }
  await saveGame(updated);
  return ok2({ game: sanitizeGame(updated) });
}
async function clearFinishedGame(userId) {
  const game = await getGameForUser(userId);
  if (game && game.phase === "finished") {
    await persistRound(userId, game);
    await syncBalance(userId, game.balance);
  }
  await clearGame(userId);
  return ok2({ ok: true });
}
function getShoeInfoForUser(userId) {
  const info = getShoeInfo(userId);
  if (!info) {
    return ok2({ cardsRemaining: null, penetration: null });
  }
  return ok2(info);
}
async function syncBalance(userId, newBalance) {
  await exports_balance.updateBalance(userId, newBalance);
}
async function findOrCreateBalance2(userId) {
  return exports_balance.findOrCreateBalance(userId);
}
async function persistRound(userId, game) {
  if (await isPersisted(game.id))
    return;
  await markPersisted(game.id);
  let totalBet = 0;
  let totalWin = 0;
  for (const hand of game.playerHands) {
    totalBet += hand.bet;
    if (hand.insuranceBet)
      totalBet += hand.insuranceBet;
    const result = hand.result;
    if (result === "blackjack")
      totalWin += Math.floor(hand.bet * 2.5);
    else if (result === "win")
      totalWin += hand.bet * 2;
    else if (result === "push")
      totalWin += hand.bet;
    if (hand.insuranceBet && hand.insuranceResult === "win") {
      totalWin += hand.insuranceBet * 3;
    }
  }
  const handsSnapshot = game.playerHands.map((h2) => ({
    result: h2.result ?? "loss",
    bet: h2.bet,
    doubled: h2.doubled ?? false,
    splitAces: h2.splitAces ?? false
  }));
  await db.insert(blackjackRound).values({
    id: crypto8.randomBytes(16).toString("hex"),
    userId,
    totalBet: totalBet.toString(),
    totalWin: totalWin.toString(),
    handsSnapshot,
    balanceAfter: game.balance.toString()
  });
}
function validateAction(action, game, hand) {
  switch (action) {
    case "double":
      if (hand.cards.length !== 2) {
        return err(ErrorCode.CANNOT_DOUBLE_NOW);
      }
      if (game.balance < hand.bet) {
        return err(ErrorCode.INSUFFICIENT_FUNDS);
      }
      return;
    case "split":
      if (!canSplit(hand.cards)) {
        return err(ErrorCode.CANNOT_SPLIT);
      }
      if (game.balance < hand.bet) {
        return err(ErrorCode.INSUFFICIENT_FUNDS);
      }
      return;
    default:
      return;
  }
}
function executeAction(action, game) {
  switch (action) {
    case "hit":
      return hitHand(game);
    case "stand":
      return standHand(game);
    case "double":
      return doubleDown(game);
    case "split":
      return splitHand(game);
  }
}

